/* Global
------------------------------- */
html[dir="rtl"][lang]{direction:rtl!important}
body{background:$(index.bg.color);color:$(body.text.color);line-height:1.42857143;margin:0;min-height:100vh}
body.single_view{background-color:$(single.bg.color)}
body.error_view{background-image:url('https://3.bp.blogspot.com/-9FmvwdH6NtA/XHNTKm-cOeI/AAAAAAAAGl4/0HFJkQHaRsA34uW44dXTclRn0uPs80RoACLcBGAs/s1600/brick-wall.png');background-repeat:repeat}
a,a:hover,a:focus{text-decoration:none;outline:none}
a,button,input,textarea,.btn,.contact-note p,.post_snippet_text,.post_share_buttons{-webkit-transition:all 0.3s ease 0s;-o-transition:all 0.3s ease 0s;transition:all 0.3s ease 0s}
a,a:focus,.uk-spinner,.uk-form-icon:hover,.uk-button-link{color:$(body.link.color)}
button{background:transparent;border:0}
.uk-totop,.uk-tab>.uk-active>a,.uk-light .uk-tab>.uk-active>a{border-color:$(body.link.color)}
.uk-tooltip,.uk-totop,.uk-open>.uk-accordion-title{background:$(body.link.color)}
li:last-child >.uk-accordion-title{border-bottom:0}
.uk-icon-button:focus,.uk-icon-button:hover,.uk-active>.uk-icon-button,.uk-icon-button:active,.uk-light .uk-icon-button:focus,.uk-light .uk-icon-button:hover,.uk-light .uk-active>.uk-icon-button,.uk-light .uk-icon-button:active,.uk-button-default:focus,.uk-button-default:hover,.uk-button-default.uk-active,.uk-button-default:active,.uk-light .uk-button-default:focus,.uk-light .uk-button-default:hover,.uk-light .uk-button-default.uk-active,.uk-light .uk-button-default:active{background-color:$(body.link.hover.color)}
.uk-button-default:focus,.uk-button-default:hover,.uk-button-default.uk-active,.uk-button-default:active,.uk-light .uk-button-default:focus,.uk-light .uk-button-default:hover,.uk-light .uk-button-default.uk-active,.uk-light .uk-button-default:active,.uk-totop:active,.uk-totop:focus,.uk-totop:hover{border-color:$(body.link.hover.color)}
a:hover,.uk-button-link:focus,.uk-button-link:hover{color:$(body.link.hover.color)}
.uk-totop:active,.uk-totop:focus,.uk-totop:hover,.uk-accordion-title:focus,.uk-accordion-title:hover{background:$(body.link.hover.color)}
.uk-slidenav,.uk-slidenav:hover,.uk-light .uk-slidenav,.uk-light .uk-slidenav:hover{color:$(keycolor)}
.uk-slidenav:not(.uk-invisible):hover{opacity:.7}
.uk-slidenav.uk-invisible{visibility:visible!important;opacity:.4}
.uk-dotnav > * > *,.uk-light .uk-dotnav > * > *{width:12px;height:12px;border:1px solid $(keycolor)}
.uk-dotnav > * >:focus,.uk-dotnav > * >:hover,.uk-dotnav > .uk-active > *,.uk-light .uk-dotnav > * >:focus,.uk-light .uk-dotnav > * >:hover,.uk-light .uk-dotnav > .uk-active > *{background:$(keycolor);border-color:transparent}
.uk-h1,.uk-h2,.uk-h3,.uk-h4,.uk-h5,.uk-h6,h1,h2,h3,h4,h5,h6{font:inherit;font-weight:500}
.uk-h1,h1{font-size:2.23125rem;line-height:1.2}
.uk-h2,h2{font-size:1.7rem;line-height:1.3}
.uk-h3,h3{font-size:1.5rem;line-height:1.4}
.uk-h4,h4{font-size:1.25rem;line-height:1.4}
.uk-h5,h5{font-size:1rem;line-height:1.4}
.uk-h6,h6{font-size:.875rem;line-height:1.4}
.item-control,.options{display:none}
.clip{border:0;clip:rect(1px,1px,1px,1px);height:1px;width:1px;overflow:hidden;padding:0;position:absolute}
.hidden{display:none!important}
.uk-offcanvas,.uk-modal,.uk-lightbox{z-index:1060}
.uk-offcanvas .uk-close{-webkit-transition:all 0.3s ease 0s;-o-transition:all 0.3s ease 0s;transition:all 0.3s ease 0s}
.uk-offcanvas .uk-close:focus{color:#fff}
.uk-light .uk-close:focus,.uk-close:hover{color:#fff}
.uk-light .uk-spinner{color:#fff}
.uk-card-hover:not(.uk-card-default):not(.uk-card-primary):not(.uk-card-secondary):hover{background:inherit}
.mark{background-color:#eee;border:1px solid #aaa;border-radius:0;cursor:default !important}
.mark.mark_empty{height:40px;width:40px;padding:0;line-height:36px;border-radius:100%!important}
*:not(pre)>code,*:not(pre)>kbd,*:not(pre)>samp{word-break:break-all}
.uk-notification-close{top:50%;transform:translateY(-50%)}
.uk-notification-close:hover{color:$(keycolor)}
.uk-notification-message{border-radius:50px;color:inherit;padding:12px 25px 12px 25px;transition:.2s ease-in-out;transition-property:box-shadow;box-shadow:0 5px 10px #00000026;font-size:85%}
.table_content{border:1px solid #eee;border-radius:4px;box-shadow:0 5px 15px rgba(0,0,0,.08)}
.table_content .table_content_title{background-image:url("data:image/svg+xml;charset=UTF-8,%3Csvg%20width%3D%2220%22%20height%3D%2220%22%20viewBox%3D%220%200%2020%2020%22%20xmlns%3D%22http://www.w3.org/2000/svg%22%20data-svg%3D%22list%22%3E%3Crect%20x%3D%226%22%20y%3D%224%22%20width%3D%2212%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%226%22%20y%3D%229%22%20width%3D%2212%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%226%22%20y%3D%2214%22%20width%3D%2212%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%222%22%20y%3D%224%22%20width%3D%222%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%222%22%20y%3D%229%22%20width%3D%222%22%20height%3D%221%22%3E%3C/rect%3E%3Crect%20x%3D%222%22%20y%3D%2214%22%20width%3D%222%22%20height%3D%221%22%3E%3C/rect%3E%3C/svg%3E");background-repeat:no-repeat;background-position:$startSide 30px top 50%;padding:12px 65px;border-bottom:1px solid rgba(0,0,0,.08)}
.table_content .uk-list{counter-reset:item_items}
.table_content .uk-list a:before{display:inline-block;margin-right:8px;content:counters(item_items,". ") ".";counter-increment:item_items;color:$(body.link.color);-webkit-transition:all 0.3s ease 0s;-o-transition:all 0.3s ease 0s;transition:all 0.3s ease 0s}
.table_content .uk-list a:hover:before{color:$(body.link.hover.color)}
.table_content .uk-list .uk-list a,.table_content .uk-list .uk-list a:before{color:#555}
.table_content > .uk-list{margin:0;padding:20px 65px;counter-reset:item}
.table_content > .uk-list > li > a:before{content:counters(item,"") ".";counter-increment:item}
.responsive_iframe{position:relative;height:0;padding-bottom:56.25%}
.responsive_iframe > *{border:0;position:absolute;width:100%;height:100%;left:0}

/* .wrapper
------------------------------- */

/* header + footer
------------------------------- */
header{background-color:$(header.bg.color.1);background-image: -webkit-gradient(linear,left top,right top,from($(header.bg.color.1)),to($(header.bg.color.2)));background-image: linear-gradient(to right,$(header.bg.color.1),$(header.bg.color.2));display:flex;flex-direction:column;padding-top:60px}
.no_waves header{-webkit-box-shadow:0 5px 15px rgba(0,0,0,.08);box-shadow:0 5px 15px rgba(0,0,0,.08)}
.compact_header header{padding-top:40px}
header .google-auto-placed,footer .google-auto-placed{display:none!important;opacity:0!important;visibility:hidden!important;height:0!important;position:absolute!important;left:0!important;top:0!important;width:0!important}

/* .topnav */
.topnav_wrapper{padding-bottom:70px}
.topnav .sidenav_button a{border-color:transparent}
.topnav .topnav_social li a{background:#333;color:#fff;font-size:0;height:40px;width:40px;line-height:40px;text-align:center}
.topnav .topnav_social li a:hover,.topnav .topnav_social li a:focus{background:$(keycolor);color:#fff}

/* .search_form */
.search_form .widget{max-width:250px}
.search_form .widget .uk-input{background:transparent;color:#fff}
.search_form .widget button{color:#fff}
.search_form .widget .uk-input{box-shadow:none;outline:2px solid rgba(255,255,255,.2);transition-property:outline}
.search_form .widget .uk-input:hover,.search_form .widget .uk-input:focus{outline:2px solid $(keycolor)}
.search_form .widget .uk-input::placeholder{opacity:1;color:#fff}

/* .mainnav */
.mainnav_holder{padding-bottom:40px}
.mainnav_wrapper:not(.uk-sticky-fixed){height:60px}
.mainnav .header-widget h1:not(.clip){display:flex;height:60px;width:100%;align-items:center;margin:0;-webkit-transition:all 0.3s ease-in-out 0s;-o-transition:all 0.3s ease-in-out 0s;transition:all 0.3s ease-in-out 0s}
.mainnav .header-image-wrapper{display:flex;height:60px;width:100%;align-items:center}
.mainnav .header-image-wrapper img{height:60px;width:auto;-webkit-transition:height 0.3s ease-in-out 0s;-o-transition:height 0.3s ease-in-out 0s;transition:height 0.3s ease-in-out 0s}
.mainnav_menu > ul > li:not(:last-child){margin-$startSide:20px;margin-$endSide:20px}
.mainnav_menu > ul > li:last-child{margin-$startSide:20px}
.mainnav_menu.header_search_enabled > ul > li:nth-last-child(2){margin-$endSide:0}
.mainnav_menu > ul > li > ul{display:none}
.mainnav_menu.uk-navbar-container{background:transparent;position:static}
.mainnav_menu .uk-navbar-nav > li > a{color:#fff;min-height:60px;font-family:inherit;font-weight:300;position:relative;padding:0;margin:0;text-transform:capitalize;transition-duration:.3s;transition-property:color,background-color,min-height}
.mainnav_menu .uk-navbar-nav > li > a:hover,.mainnav_menu .uk-navbar-nav > li > a:focus{color:#fff}
.mainnav_menu .uk-navbar-nav > li > a:before{background:#fff;content:'';display:block;position:absolute;$startSide:0;$endSide:100%;bottom:0;height:1px;background-color:currentColor;transition:all .3s ease-in-out}
.mainnav_menu .uk-navbar-nav > li:hover > a:before,.mainnav_menu .uk-navbar-nav > li > a.uk-open:before,.mainnav_menu .uk-navbar-nav > li.current > a:before{$endSide:0}
.mainnav_menu .uk-navbar-nav > li > a.uk-open:after{$endSide:0}
.mainnav_menu .uk-navbar-nav > li > a:not(.icon_search) svg{-webkit-transition:all 0.3s ease 0s;-o-transition:all 0.3s ease 0s;transition:all 0.3s ease 0s}
.mainnav_menu .uk-navbar-nav > li > a.uk-open:not(.icon_search) svg{-webkit-transform:rotate(45deg);transform:rotate(45deg)}
.mainnav_menu .uk-navbar-nav > li li{position:relative}
.mainnav_menu .uk-navbar-nav > li li .uk-navbar-dropdown{top:0!important}
.mainnav_menu .uk-navbar-nav > li li a{font-size:90%}
/*.mainnav_menu .uk-navbar-nav > li li a:not(.uk-icon-button),.mainnav_menu .uk-navbar-nav > li li a:not(.uk-icon-button):focus{color:#999}*/
.mainnav_menu .uk-navbar-nav li li:hover > a,.mainnav_menu .uk-navbar-nav li li.current > a{color:$(keycolor)}
.mainnav_menu .uk-navbar-nav .uk-navbar-dropdown{min-width:200px;width:auto;margin-top:0;top:60px!important}
.mainnav_menu .mega_menu,.mainnav_menu .big_menu{$startSide:40px!important;$endSide:0!important}
.mainnav_menu .mega_menu{background:#f1f1f1;padding:0;top:60px!important}
.mainnav_menu .has_single_mega > .mega_menu{padding:0 25px 25px}
.thumb_video,.thumb_external{background-position:center;background-repeat:no-repeat;background-size:cover}
.thumb_video img,.thumb_external img{opacity:0}
.mainnav_menu .mega_menu .blog_posts > li{margin-top:25px}
.mainnav_menu .mega_menu .post_thumbnail a,.main_slider [data-uk-slider] .post_thumbnail a{color:#fff}
.mainnav_menu .mega_menu .post_content{padding:15px!important}
.mainnav_menu .mega_menu .post_title,.main_slider [data-uk-slider] .post_title,.tagged .blog_posts .post_title{font-size:16px;line-height:1.4;margin-bottom:15px}
.mainnav_menu .mega_menu .post_title a,.main_slider [data-uk-slider] .post_title a{color:#333}
.mainnav_menu .mega_menu .uk-tab{background:#fff;height:100%;margin-$endSide:0;overflow:hidden;padding-top:20px;padding-bottom:20px;padding-$startSide:20px;padding-$endSide:0}
.mainnav_menu .mega_menu .uk-tab:before,.mainnav_menu .mega_menu .uk-tab:after{display:none}
.mainnav_menu .mega_menu .uk-tab > li > a{border-$endSide:0;padding:13px 15px;-webkit-transition:all 0.3s ease 0s;-o-transition:all 0.3s ease 0s;transition:all 0.3s ease 0s}
.mainnav_menu .mega_menu .uk-tab > .uk-active > a,.mega_menu .uk-tab > li:hover > a:hover{border:0;background:#f1f1f1;color:$(keycolor);border-top-$startSide-radius:50px;border-bottom-$startSide-radius:50px;padding-$startSide:15px}
.mainnav_menu .mega_menu .uk-switcher{padding-bottom:25px;padding-$endSide:25px;padding-$startSide:16px}
.mainnav_menu .mega_menu .more_blog_posts a,.tagged .more_blog_posts a{width:40px;height:40px;$startSide:50%;text-transform:uppercase;font-weight:300;font-size:14px;transform:translateX(-50%)}
html[dir="rtl"] .mainnav_menu .mega_menu .more_blog_posts a{transform:translateX(50%)}
.mainnav_menu .mega_menu .more_blog_posts a:hover,.tagged .more_blog_posts a:hover{width:auto;padding:0 30px}
.mainnav_menu .mega_menu .more_blog_posts a span,.tagged .more_blog_posts a span{display:none}
.mainnav_menu .mega_menu .more_blog_posts a:hover span,.tagged .more_blog_posts a:hover span{display:inline-block}
.mega[data-label] [data-uk-spinner]{min-height:100px;line-height:100px}
.featured_error,.no_results,.no_matching_results:before{color:#ff0000;line-height:1.5}
.has_single_mega .featured_error{text-align:center}
.no_results,.no_matching_results:before{background:#fff;padding:20px 25px;border-radius:4px;-webkit-box-shadow:0 5px 15px rgba(0,0,0,.08);box-shadow:0 5px 15px rgba(0,0,0,.08)}
.no_matching_results:before{width:100%;margin-$startSide:40px}
.mainnav_menu .big_menu > ul{margin-$startSide:-25px}
.mainnav_menu .big_menu > ul > li{padding-$startSide:25px}
.mainnav_menu .mega_menu .list .post_content,.sidemenu li.has_mega .list .post_content{padding:0!important}
.mainnav_menu .mega_menu .list .post_thumbnail a img,.sidemenu li.has_mega .list .post_thumbnail a img{width:72px;height:72px}
.mainnav_menu .has_mega .featured_error{padding-top:25px}

/* .uk-navbar-sticky */
.mainnav_wrapper.uk-sticky-fixed{background-color:$(header.bg.color.1);background-image: -webkit-gradient(linear,left top,right top,from($(header.bg.color.1)),to($(header.bg.color.2)));background-image: linear-gradient(to right,$(header.bg.color.1),$(header.bg.color.2));-webkit-box-shadow:0 5px 15px rgba(0,0,0,.08);box-shadow:0 5px 15px rgba(0,0,0,.08);z-index:1020}
.mainnav_wrapper.uk-sticky-fixed .mainnav .Header .header-widget h1:not(.clip){height:50px;font-size:24px}
.mainnav_wrapper.uk-sticky-fixed .mainnav .Header .header-image-wrapper{height:50px}
.mainnav_wrapper.uk-sticky-fixed .mainnav .Header .header-image-wrapper img{height:40px}
.mainnav_wrapper.uk-sticky-fixed .mainnav .mainnav_menu .uk-navbar-nav > li > a{min-height:50px}
.mainnav_wrapper.uk-sticky-fixed .mainnav .mainnav_menu .uk-navbar-dropdown,.mainnav_wrapper.uk-sticky-fixed .mainnav .mainnav_menu .mega_menu,.mainnav_wrapper.uk-sticky-fixed .mainnav .mainnav_menu .big_menu{top:50px!important}
.mainnav_wrapper.uk-sticky-fixed .mainnav .mainnav_menu .uk-navbar-nav > li li .uk-navbar-dropdown{top:0!important}

/* .sidemenu */
.sidemenu ul,.sidemenu li{list-style:none;margin:0;padding:0}
.sidemenu .uk-accordion{border:0;border-radius:0;box-shadow:none}
.sidemenu .sidemenu_list{padding:80px 0;border-bottom:0}
.sidemenu .sidemenu_list :not(.post_thumbnail):not(.post_title):not(.more_blog_posts) > a{background:transparent;display:block;position:relative;font-size:inherit;line-height:inherit;border-bottom:0;text-transform:none;padding:12px 30px}
.sidemenu.uk-light .sidemenu_list :not(.post_thumbnail):not(.post_title) > a{color:#fff}
.sidemenu .sidemenu_list :not(.post_thumbnail):not(.post_title):not(.more_blog_posts) > a > span{color:#222;float:$endSide;line-height:inherit;-webkit-transition:all 0.3s ease 0s;-o-transition:all 0.3s ease 0s;transition:all 0.3s ease 0s}
.sidemenu .sidemenu_list :not(.post_thumbnail):not(.post_title):not(.more_blog_posts) > a:hover > span{color:#fff}
.sidemenu.uk-light .sidemenu_list :not(.post_thumbnail):not(.post_title) > a > span{color:#fff}
.sidemenu .sidemenu_list .current > a,.sidemenu .sidemenu_list .current > div > a{border-$startSide:3px solid $(keycolor);padding-$startSide:27px}
.sidemenu .sidemenu_list .current > a,.sidemenu .sidemenu_list .current > div > a,.sidemenu .sidemenu_list .uk-open > a,.sidemenu .sidemenu_list li > a:focus,.sidemenu .sidemenu_list li > div > a:focus{color:$(keycolor)!important}
.sidemenu .sidemenu_list li > a:hover,.sidemenu .sidemenu_list li > div > a:hover{background:$(keycolor)!important;color:#fff!important}
.sidemenu .sidemenu_list > li ul,.sidemenu .sidemenu_list li.has_single_mega .mega,.sidemenu .sidemenu_list li .featured_error,.sidemenu .sidemenu_list > li .more_blog_posts{background:#e8e8e8;border-bottom:0}
.sidemenu.uk-light .sidemenu_list > li ul,.sidemenu.uk-light .sidemenu_list li .mega,.sidemenu.uk-light .sidemenu_list li .featured_error,.sidemenu.uk-light .sidemenu_list > li .more_blog_posts{background:#333}
.sidemenu .sidemenu_list > li ul :not(.post_thumbnail):not(.post_title) > a{font-size:14px}
.sidemenu .sidemenu_list > li ul ul,.sidemenu .sidemenu_list > li ul .more_blog_posts{background:#d8d8d8;padding:0}
.sidemenu .sidemenu_list li .featured_error{background:#333;color:#fff;padding:30px;text-align:center}
.sidemenu.uk-light .sidemenu_list li .featured_error{color:#ff0000}
.sidemenu .sidemenu_list li.has_single_mega .blog_posts{padding:30px}
.sidemenu .sidemenu_list li.has_single_mega .blog_posts li{margin-bottom:30px}
.sidemenu .sidemenu_list li.has_single_mega .blog_posts li:last-child{margin-bottom:0}
.sidemenu .sidemenu_list li.has_multi_mega ul{padding-$startSide:0}
.sidemenu .sidemenu_list li.has_multi_mega .blog_posts{padding:30px}
.sidemenu .sidemenu_list li.has_multi_mega .mega,.sidemenu .sidemenu_list li.has_multi_mega .featured_error{background:#d8d8d8}
.sidemenu.uk-light .sidemenu_list > li ul ul,.sidemenu.uk-light .sidemenu_list li.has_multi_mega .mega,.sidemenu.uk-light .sidemenu_list li.has_multi_mega .featured_error,.sidemenu.uk-light .sidemenu_list > li ul .more_blog_posts{background:#444}
.sidemenu .sidemenu_list li.has_multi_mega .blog_posts li{margin-bottom:30px}
.sidemenu .sidemenu_list li.has_multi_mega .blog_posts li:last-child{margin-bottom:0}
.sidemenu .sidemenu_list li.has_mega .blog_posts .post_title{font-size:14px;line-height:24px}

/* main
------------------------------- */
main{position:relative;z-index:3}
main .main_slider .main_slider_section > .widget,main .full_ads_section:not(.bottom) > .widget{margin-top:50px}
main .full_ads_section.bottom > .widget{margin-bottom:50px}
main .main_content{margin-top:50px;margin-bottom:70px}

/* .main_slider */
.main_slider .slideshow,.main_slider .carousel{position:relative}
.main_slider .slideshow{min-height:calc(1140px / 2.1105)}
.main_slider .carousel{min-height:300px}
.main_slider .slideshow .uk-spinner,.main_slider .carousel .uk-spinner{position:absolute;top:calc(50% - 15px);left:calc(50% - 15px)}
.main_slider li.slider_item{text-shadow:0 0 2px #000}
.main_slider li.slider_item h3{font-size:24px}
.main_slider li.slider_item p{font-size:15px;color:#ddd}
.main_slider li.slider_item .post_meta{font-size:12px;color:#ddd}
.main_slider li.slider_item .thumb img{width:100%}
.main_slider [data-uk-slider]{margin-$startSide:-20px;margin-$endSide:-20px;padding-$startSide:20px;padding-$endSide:20px;padding-bottom:20px;margin-bottom:-20px}
.main_slider [data-uk-slideshow] .uk-icon-button,.main_slider [data-uk-slider] .uk-icon-button{background-color:#fff;color:#333;height:40px;width:40px;line-height:40px}
.main_slider [data-uk-slideshow] .uk-icon-button:hover,.main_slider [data-uk-slider] .uk-icon-button:hover{background-color:$(body.link.hover.color);color:#fff}
.main_slider [data-uk-slider] .uk-icon-button{position:absolute;$startSide:20px;bottom:25px}
.main_slider [data-uk-slider] .uk-icon-button[data-uk-slider-item="next"]{$startSide:auto;$endSide:20px}
.main_slider [data-uk-slideshow] .uk-slideshow-nav{margin:20px 0 0}
.main_slider [data-uk-slider] .uk-slider-nav{margin:40px 0 20px}

/* .top_bg + .bottom_bg */
.top_bg > svg:not(.hidden),.bottom_bg > svg:not(.hidden){display:block}
.top_bg > svg{margin-bottom:-1px}
.bottom_bg > svg{margin-top:-1px}
.top_bg > :not(svg):(.full_header),.top_bg svg :not(path):not(clipPath):not(linearGradient):not(stop):not(defs):not(pattern):not(rect):not(image),.bottom_bg > :not(svg):(.full_header),.bottom_bg svg :not(path):not(clipPath):not(linearGradient):not(stop):not(defs):not(pattern):not(rect):not(image){display:none!important;border:0!important;clip:rect(1px,1px,1px,1px)!important;height:1px!important;width:1px!important;overflow:hidden!important;padding:0!important;position:absolute!important;margin:0!important;opacity:0!important;visibility:hidden!important;top:-9999999px;left:-9999999px;font-size:0!important;line-height:0!important}
.top_bg svg .g_fill_2{color:$(header.bg.color.1)}
.top_bg svg .g_fill_3{color:$(header.bg.color.2)}
.bottom_bg svg .g_fill_2{color:$(footer.bg.color.1)}
.bottom_bg svg .g_fill_3{color:$(footer.bg.color.2)}
body.multiple_view .top_bg svg .g_fill_1,body.multiple_view .bottom_bg svg .g_fill_1{color:$(index.bg.color)}
body.single_view .top_bg svg .g_fill_1,body.single_view .bottom_bg svg .g_fill_1{color:$(single.bg.color)}
body.error_view .top_bg svg .g_fill_1,body.error_view .bottom_bg svg .g_fill_1{color:transparent}
body.single_view .top_bg.has_full_header svg .g_fill_1{color:#fff;opacity:0.92}
body.error_view .top_bg,body.error_view .bottom_bg{background-color:$(index.bg.color);background-image:url('https://3.bp.blogspot.com/-9FmvwdH6NtA/XHNTKm-cOeI/AAAAAAAAGl4/0HFJkQHaRsA34uW44dXTclRn0uPs80RoACLcBGAs/s1600/brick-wall.png');background-repeat:repeat;background-position:center}

/* .filtering_labels */
.filtering_labels .select_label a{padding:0 10px}
.filtering_labels .select_label a:not(.uk-active):not(:hover):not(:active):not(:focus){border-color:#fff}
.filtering_labels .select_view a{height:40px;width:40px}
.filtering_labels .breadcrumb .uk-breadcrumb li a,.breadcrumb .uk-breadcrumb li span{text-transform:uppercase;line-height:40px;font-size:14px;font-weight:300;letter-spacing:1px}
.filtering_labels .breadcrumb .uk-breadcrumb li a{color:$(keycolor)}
.filtering_labels .breadcrumb .uk-breadcrumb li a:hover,.breadcrumb .uk-breadcrumb li span{color:#333}

/* .blog_posts + .blog_pager */
.blog_posts .post_thumbnail a{color:#fff}
.blog_posts .post_thumbnail a img{display:block;width:100%}
.blog_posts .post_title{font-size:18px;font-weight:500;line-height:28px;text-transform:uppercase}
.blog_posts .post_title a{color:#333}
.uk-light .blog_posts .post_title a{color:#fff}
.blog_posts .post_title a:hover,.blog_posts .post_title a:focus{color:$(keycolor)}
.blog_posts .post_labels a{font-size:13px;font-weight:300}
.blog_posts .post_snippet{font-size:14px;font-weight:300;line-height:24px;color:#777766;margin-bottom:30px}
.blog_posts .post_snippet p{margin:0}
.blog_posts .post_snippet_text,.blog_posts .post_snippet.open .post_share_buttons{opacity:1;visibility:visible}
.blog_posts .post_snippet.open p,.blog_posts .post_snippet .post_share_buttons{opacity:0;visibility:hidden}
.blog_posts .post_snippet.post_snippet_off{margin-bottom:0}
.blog_posts .post_snippet.post_snippet_off .post_share_buttons{top:auto;transform:translateX(-50%);bottom:20px;box-shadow:0 5px 15px rgba(0,0,0,.08);background:#fff;padding:15px}
.blog_posts .post_share_buttons span,.single_post .post_share_buttons span{background:#333;color:#fff;line-height:36px;cursor:pointer;margin:5px}
.single_post .post_share_buttons span{margin-top:0;margin-$startSide:10px;margin-bottom:10px;margin-$endSide:0}
.blog_posts .post_share_buttons span:hover,.blog_posts .post_share_buttons span:focus,.single_post .post_share_buttons span:hover,.single_post .post_share_buttons span:focus{background:$(body.link.hover.color);color:#fff;line-height:36px}
.blog_posts .post_share_buttons.small span{line-height:25px;width:25px;height:25px}
.blog_posts .post_share_buttons.small span svg{width:15px;height:15px}
.blog_posts .post_meta,.main_slider [data-uk-slider] .post_meta{font-size:11px;font-weight:300;color:#333;text-transform:uppercase;letter-spacing:.5px}
.uk-light .blog_posts .post_meta,.uk-light .main_slider [data-uk-slider] .post_meta{color:#bbb}
.blog_posts .post_meta .post_share .action{cursor:pointer}
.blog_posts .post_meta .post_share .action:hover,.blog_posts .post_meta .post_share .action.uk-active{color:$(keycolor)}
.blog_posts .post_labels a:hover,.blog_posts .post_snippet_text a:hover,.blog_posts .post_body a:hover{text-decoration:underline}
.blog_posts .list_view .uk-card {padding:20px}
.blog_posts .list_view .post_content{padding:0}
.blog_pager a:not(:hover):not(:active):not(:focus){border-color:#fff}
.blog_pager a.loading,.blog_pager a.loading:hover{cursor:default;background:#fff;color:$(keycolor);padding:5px;border:0;line-height:0}
.blog_pager .numbering{margin-bottom:-15px}
.blog_pager .numbering a,.blog_pager .numbering .mark,.blog_pager .numbering .current,.blog_pager .numbering .jump{margin-bottom:15px}
.blog_pager .numbering .current{background-color:$(body.link.hover.color);color:#fff;cursor:default}
.blog_pager .numbering .jump input,.blog_pager .numbering .jump a{height:38px;border-radius:0;font-weight:400}
.blog_pager .numbering .jump input.error{box-shadow:0 5px 10px rgba(0,0,0,.15), 0 0 0 2px #ff3547}
.blog_pager .numbering .jump a{color:#333}
.blog_pager .numbering .jump a:focus,.blog_pager .numbering .jump a:hover{color:#fff}

/* .inline_banner */
.single_post .inline_banner{margin-bottom:30px}
.inline_banner_demo{background:#f9f9f9;border:1px dashed #e5e5e5;width:100%;max-width:100%;margin:0 auto;text-align:center;font-size:14px;text-transform:uppercase}
.inline_banner_demo[data-height="250"]{height:250px;line-height:250px}
.inline_banner_demo[data-height="90"]{height:90px;line-height:90px}

/* .single_post + .full_header */
.single_post .post_title,.single_post .post_header,.single_post .post_footer,.full_header .post_title,.full_header .post_header{font-weight:300;font-size:38px}
.single_post .post_header,.full_header .post_header{font-size:12px}
.single_post .post_header a,.single_post .post_footer a,.full_header .post_header a,.full_header .post_footer a{color:$(keycolor)}
.single_post .post_header a:hover,.single_post .post_footer a:hover,.full_header .post_header a:hover,.full_header .post_footer a:hover{color:#333}
.single_post .post_header .post_header_line > span,.single_post .post_footer .post_footer_line > span,.full_header .post_header .post_header_line > span,.full_header .post_footer .post_footer_line > span{display:inline-block}
.single_post .post_header .post_header_line .post_reactions iframe,.single_post .post_footer .post_footer_line .post_reactions iframe,.full_header .post_header .post_header_line .post_reactions iframe,.full_header .post_footer .post_footer_line .post_reactions iframe{height:26px}
