.single_post .post_share_buttons{margin-bottom:-10px!important}
.single_post .post_footer{font-size:14px}
.single_post .post_author_profile{background:#f9f9f9;border:1px solid #f1f1f1;padding:20px;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.05);box-shadow:0 5px 10px rgba(0,0,0,0.05)}
.single_post .post_author_profile .post_author_profile_photo img,.single_post .post_author_profile .post_author_profile_name img{border-radius:500px;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.15);box-shadow:0 5px 10px rgba(0,0,0,0.15)}
.single_post .post_author_profile .post_author_profile_name{font-weight:500}
.single_post .post_author_profile .post_author_profile_desc{font-weight:300;color:#444;line-height:1.6}
.single_post .post_pager{position:relative}
.single_post .post_pager a{border:1px solid #f1f1f1;padding:20px;padding-$startSide:38px;display:block;text-transform:uppercase;position:relative}
.single_post .post_pager a.blog-pager-older-link{text-align:$endSide;padding:20px;padding-$endSide:38px}
.single_post .post_pager a strong{display:block;font-size:12px}
.single_post .post_pager a .text{margin-top:10px;display:block;font-size:14px;font-weight:300;color:#444}
.single_post .post_pager a .uk-icon{position:absolute;top:50%;$startSide:-18px;margin-top:-18px}
.single_post .post_pager a:hover .uk-icon{background-color:$(body.link.hover.color);color:#fff}
.single_post .post_pager a.blog-pager-older-link .uk-icon{$endSide:-18px;$startSide:auto}
.full_header{padding:50px 0;position:relative;-webkit-box-shadow:0 5px 15px rgba(0,0,0,.08);box-shadow:0 5px 15px rgba(0,0,0,.08)}
.full_header:before{content:'';position:absolute;top:0;$startSide:0;width:100%;height:100%;z-index:1;background:#fff;opacity:0.92}
.full_header .uk-container{position:relative;z-index:2}
.full_header .post_header{margin-bottom:0!important}
.has_full_header{position:relative;background-color:#fff;background-repeat:no-repeat;background-size:cover;background-position:center}
.has_full_header > svg{position:relative;z-index:2}

/* .post_body */
.single_post .post_body{line-height:1.6}
.single_post .post_body a:hover{text-decoration:underline}
.single_post .post_body a.uk-button:hover{text-decoration:none;color:#fff}
