.single_post .post_comments:not(.uk-width-auto){background:#fff;border:1px solid #f1f1f1;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.05);box-shadow:0 5px 10px rgba(0,0,0,0.05)}
