.single_post .post_comments .post_comments_content li .avatar-image-container:after,.single_post .post_comments .post_comments_content li .avatar-image-container:after{clear:both}
.single_post .post_comments .post_comments_content li .avatar-image-container > img{background:url(https://1.bp.blogspot.com/-XmT8XvocSSo/XmOp7pvCRgI/AAAAAAAAG28/K9tbDKWdh5UrbaGFeRfC674UsN0INbUYgCLcBGAsYHQ/s1600/user.png);background-repeat:repeat;background-position-x:0%;background-position-y:0%;background-size:auto auto;background-size:35px;background-repeat:no-repeat;background-position:center;border-radius:500px;float:$startSide;height:45px;width:45px;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.15);box-shadow:0 5px 10px rgba(0,0,0,0.15)}
/*.single_post .post_comments .post_comments_content ol ol li .avatar-image-container > img{height:50px;width:50px}*/
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header{font-size:14px;font-weight:300;position:absolute;top:50%;$startSide:65px;border-$startSide:1px solid #eee;padding-$startSide:20px;z-index:1;-webkit-transform:translateY(-50%);transform:translateY(-50%)}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header cite a{font-weight:500}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header a{color:currentColor;font-style:normal;text-transform:uppercase}
