.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header .icon.blog-author{margin-$startSide:10px}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header .icon.blog-author:after{background:$(keycolor);color:#fff;border-radius:4px;content:'Admin';font-size:11px;padding:2px 5px}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-header .datetime{margin-top:4px;text-transform:lowercase;font-size:12px;display:block;color:#777}
.single_post .post_comments .post_comments_content li .comment-block{font-size:15px;padding-$startSide:85px}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-actions{font-size:13px;font-weight:300;letter-spacing:1px;$endSide:0;top:50%;text-transform:uppercase;position:absolute;z-index:2;-webkit-transform:translateY(-50%);transform:translateY(-50%)}
.single_post .post_comments .post_comments_content li .avatar-image-container .comment-actions > * + *{margin-$startSide:15px}
