/*.single_post .post_comments .post_comments_content .comment-thread ol ol li:before{background:rgba(0,0,0,.1);content:'';height:1px;top:0;$startSide:20px;$endSide:20px;position:absolute;z-index:200}*/
.single_post .post_comments .post_comments_content .comment-thread ol ol li:first-child{margin-top:30px}
.single_post .post_comments .post_comments_content .comment-thread ol ol li:first-child:before{display:none}
.single_post .post_comments .post_comments_content li .comment-block .comment-content{margin-bottom:0}
.single_post .post_comments .post_comments_content li .comment-block .deleted-comment{font-style:italic;color:#999;font-size:14px}
.single_post .post_comments iframe#comment-editor{background:#fff url(https://4.bp.blogspot.com/-zxnrT9a3Ofw/XmRFpRDiP0I/AAAAAAAAG3M/tXY-lGS4Z1ktmizov2u8wR2hGrKRAgPpwCLcBGAsYHQ/s1600/loader_light.gif) no-repeat center;margin-top:30px;padding-$startSide:9px;padding-$endSide:12px;border:1px dashed #ccc;max-width:100%;box-sizing:border-box}
html[dir="rtl"] .single_post .post_comments iframe#comment-editor{padding-$startSide:10px;padding-$endSide:12px}
.single_post .post_comments .post_comments_content .loadmore{margin-top:20px}
.single_post .post_comments .post_comments_content .loadmore.loaded{max-height:0;opacity:0;overflow:hidden;margin-top:0}
.single_post .post_comments .post_comments_content .post_comments_message{background:#eee;border-radius:5px;margin-top:20px;padding:12px 20px;-webkit-box-shadow:0 5px 10px rgba(0,0,0,0.05);box-shadow:0 5px 10px rgba(0,0,0,0.05)}
.single_post .post_comments .continue{margin-top:20px}
.single_post .post_comments .continue a{line-height:20px;display:inline-block}
.single_post .post_comments ol .continue,.single_post .post_comments .comments_locked .continue,.single_post .post_comments .comment-thread .thread-count,/*.single_post .post_comments .post_comments_content .post_comments_form,*/.single_post .post_comments .post_comments_content.comments_locked li .avatar-image-container .comment-actions > a{display:none!important}
.single_post .post_comments .comments_emotions .comments_emotions_button{user-select:none}
